export async function getForceResetInstructionAsync<
  TAccountAuthority extends string,
  TAccountMarket extends string,
  TAccountHistogram extends string,
  TAccountOrderSlab extends string,
  TProgramAddress extends Address = typeof TEMPO_PROGRAM_PROGRAM_ADDRESS,
>(
  input: ForceResetAsyncInput<
    TAccountAuthority,
    TAccountMarket,
    TAccountHistogram,
    TAccountOrderSlab
  >,
  config?: { programAddress?: TProgramAddress },
): Promise<
  ForceResetInstruction<
    TProgramAddress,
    TAccountAuthority,
    TAccountMarket,
    TAccountHistogram,
    TAccountOrderSlab
  >
> {
  // Program address.
  const programAddress =
    config?.programAddress ?? TEMPO_PROGRAM_PROGRAM_ADDRESS;

  // Original accounts.
  const originalAccounts = {
    authority: { value: input.authority ?? null, isWritable: false },
    market: { value: input.market ?? null, isWritable: true },
    histogram: { value: input.histogram ?? null, isWritable: true },
    orderSlab: { value: input.orderSlab ?? null, isWritable: true },
  };
  const accounts = originalAccounts as Record<
    keyof typeof originalAccounts,
    ResolvedInstructionAccount
  >;

  // Resolve default values.
  if (!accounts.histogram.value) {
    accounts.histogram.value = await findAuctionHistogramHeaderPda({
      market: getAddressFromResolvedInstructionAccount(
        "market",
        accounts.market.value,
      ),
    });
  }
  if (!accounts.orderSlab.value) {
    accounts.orderSlab.value = await findOrderSlabHeaderPda({
      market: getAddressFromResolvedInstructionAccount(
        "market",
        accounts.market.value,
      ),
    });
  }

  const getAccountMeta = getAccountMetaFactory(programAddress, "omitted");
  return Object.freeze({
    accounts: [
      getAccountMeta("authority", accounts.authority),
      getAccountMeta("market", accounts.market),
      getAccountMeta("histogram", accounts.histogram),
      getAccountMeta("orderSlab", accounts.orderSlab),
    ],
    data: getForceResetInstructionDataEncoder().encode({}),
    programAddress,
  } as ForceResetInstruction<
    TProgramAddress,
    TAccountAuthority,
    TAccountMarket,
    TAccountHistogram,
    TAccountOrderSlab
  >);
}

